import javax.xml.soap.*;
import javax.xml.parsers.DocumentBuilder;
import javax.xml.parsers.DocumentBuilderFactory;
import javax.xml.ws.*;
import javax.xml.ws.handler.MessageContext;
import org.w3c.dom.Document;
import org.w3c.dom.NodeList;

@WebService
public class XMLProcessingService {

    @WebMethod
    public String processXML(SOAPMessage request) {
        try {
            // Extract the SOAP body
            SOAPBody body = request.getSOAPBody();
            DocumentBuilderFactory factory = DocumentBuilderFactory.newInstance();
            DocumentBuilder builder = factory.newDocumentBuilder();
            Document doc = builder.parse(new ByteArrayInputStream(body.getTextContent().getBytes()));

            // Process the XML document
            return processDocument(doc);
        } catch (Exception e) {
            e.printStackTrace();
            return "Error processing XML.";
        }
    }

    private String processDocument(Document doc) {
        // Handle large XML and nested structures
        NodeList nodes = doc.getElementsByTagName("Entity");
        StringBuilder response = new StringBuilder("Processed Entities:\n");
        
        for (int i = 0; i < nodes.getLength(); i++) {
            // Assume each entity has a name and nested elements
            String entityName = nodes.item(i).getAttributes().getNamedItem("name").getNodeValue();
            response.append("Entity: ").append(entityName).append("\n");
            // Process any nested entities here as needed
        }
        
        return response.toString();
    }
}